class Solution:
    def checkArray(self, nums, k):
        n = len(nums)
        arr = list(nums)
        for i in range(n):
            if arr[i] < 0:
                return False
            if arr[i] == 0:
                continue
            if i + k > n:
                return False
            need = arr[i]
            for j in range(i, i + k):
                arr[j] -= need
                if arr[j] < 0:
                    return False
        return all(x == 0 for x in arr)

